+ * 1. Parses & validates input (date strings → Date objects, enum checks).
+ * 2. Delegates to AnalyticsService.
+ * 3. Returns a typed response (or throws an Error for the framework to map
+ *    to an HTTP status code).
+ */
+
+import type { AnalyticsService } from '../services/analytics.service.js';
+import type {
+  AnalyticsQuery,
+  DashboardData,
+  MetricResponse,
+  MetricType,
+  TimeGranularity,
