+  {
+    method: 'GET',
+    path: '/api/analytics/dashboard',
+    description: 'Full dashboard snapshot with all widgets',
+  },
+  {
+    method: 'GET',
+    path: '/api/analytics/metrics/:metricType',
+    description: 'Summary + time series for a single metric',
+  },
+];
+
+// ---------------------------------------------------------------------------
+// Shared validation helpers
+// ---------------------------------------------------------------------------
+
+const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];
+const VALID_METRIC_TYPES: MetricType[] = [
+  'revenue',
+  'orders',
+  'users',
+  'average-order-value',
+];
