 * and any consuming route handler or client. Downstream implementers
 * should build aggregation logic that produces these shapes from the
 * existing Order and User data.
 */

// ---------------------------------------------------------------------------
// Query parameters
// ---------------------------------------------------------------------------

/**
 * Granularity for time-series data points.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
