}

/**
 * Query parameters for the metrics endpoint.
 */
export interface MetricsQuery extends AnalyticsQuery {
  /** Which metric to retrieve */
  metricType: MetricType;
}

// ---------------------------------------------------------------------------
// Response shapes
// ---------------------------------------------------------------------------

/**
 * A single data point in a time series.
 */
export interface TimeSeriesPoint {
  /** Start of the time bucket (ISO-8601) */
  timestamp: Date;
  /** Aggregated value for this bucket */
  value: number;
  /** Optional label (e.g. "Mon", "Week 12") */
  label?: string;
}

/**
 * Summary statistics for a single metric.
 */
export interface MetricSummary {
