  userId: string;
  userName: string;
  totalOrders: number;
  totalRevenue: number;
}

/**
 * Full dashboard payload returned by GET /api/analytics/dashboard.
 * Provides a high-level snapshot so the UI can render all widgets
 * in a single request.
 */
export interface DashboardData {
  /** Summary cards at the top of the dashboard */
  metrics: MetricSummary[];
  /** Revenue over time for the primary chart */
  revenueTimeSeries: TimeSeriesPoint[];
  /** Orders over time for the secondary chart */
  ordersTimeSeries: TimeSeriesPoint[];
  /** Donut / pie chart data */
  orderStatusBreakdown: OrderStatusBreakdown[];
  /** Leaderboard widget */
  topUsers: TopUser[];
  /** When this snapshot was computed */
  generatedAt: Date;
}

/**
 * Response wrapper for a single metric endpoint.
 */
export interface MetricResponse {
  summary: MetricSummary;
  timeSeries: TimeSeriesPoint[];
  query: {
    metricType: MetricType;
    startDate: Date;
    endDate: Date;
    granularity: TimeGranularity;
